{"path": "check_arkham.py", "content": "#!/usr/bin/env python3
"""Check for Arkham API credentials"""

import os
import imaplib
import email
import re
from email.header import decode_header

try:
    from dotenv import load_dotenv
    load_dotenv()
except:
    pass

EMAIL_USER = os.getenv('EMAIL_USER', 'cryptorugmuncher@gmail.com')
EMAIL_PASSWORD = os.getenv('EMAIL_PASSWORD', '')

def check_arkham():
    mail = imaplib.IMAP4_SSL('imap.gmail.com', 993)
    mail.login(EMAIL_USER, EMAIL_PASSWORD)
    mail.select('INBOX')

    status, messages = mail.search(None, 'FROM "arkham"')

    if status != 'OK' or not messages[0]:
        print('No Arkham emails found')
        return

    email_ids = messages[0].split()
    print(f'Found {len(email_ids)} Arkham email(s)\n')

    for email_id in email_ids:
        status, msg_data = mail.fetch(email_id, '(RFC822)')
        if status != 'OK':
            continue

        msg = email.message_from_bytes(msg_data[0][1])

        subject = ''
        if msg['Subject']:
            subject = decode_header(msg['Subject'])[0][0]
            if isinstance(subject, bytes):
                subject = subject.decode()

        print(f'📧 {subject}')
        print(f'   Date: {msg.get("Date", "")}')

        # Get body
        body = ''
        if msg.is_multipart():
            for part in msg.walk():
                if part.get_content_type() == 'text/plain':
                    try:
                        body = part.get_payload(decode=True).decode()
                        break
                    except:
                        pass
        else:
            try:
                body = msg.get_payload(decode=True).decode()
            except:
                pass

        # Look for API key patterns
        api_patterns = [
            r'api[_\s-]?key[:\s]+([a-zA-Z0-9_-]{10,})',
            r'apikey[=:\s]+([a-zA-Z0-9_-]{10,})',
            r'key[=:\s]+([a-zA-Z0-9_-]{20,})',
        ]

        for pattern in api_patterns:
            matches = re.findall(pattern, body, re.IGNORECASE)
            for match in matches:
                masked = f'{match[:8]}...{match[-4:]}' if len(match) > 12 else match
                print(f'   🔑 API Key: {masked}')

        # Look for links
        links = re.findall(r'https?://[^\s<>"{}|\\^`[\]]+', body)
        dashboard_links = [l for l in links if 'arkham' in l and ('dashboard' in l or 'api' in l)]
        if dashboard_links:
            print(f'   🔗 Dashboard: {dashboard_links[0]}')

    mail.logout()

if __name__ == '__main__':
    check_arkham()
"}

